test.config:
indexer
{
	mem_limit			= 16M
}

searchd
{

}

source src_t
{
	type				= mysql

	sql_query			= select id, a, b from test_t
	sql_attr_uint		= a
	sql_attr_uint		= b
}

index t
{
	source			= src_t
	path			= /t
}

source src_books
{
	type				= mysql

	sql_query			= select id, author_id, page_count, year from test_books
	sql_attr_uint		= author_id
	sql_attr_uint		= page_count
	sql_attr_uint		= year
}

index books
{
	source			= src_books
	path			= /books
}

test.db_create:
create table test_t
(
	id int not null,
	a int not null,
	b int not null
);

queries.sphinxql:
select count(distinct a) as c1 from t; select count(distinct b) as c2 from t;
select * from t group by a; select count(distinct a) as c3 from t;
select count(distinct author_id) as cnt, groupby() as page_count from books group by page_count order by page_count asc; select count(distinct author_id) as cnt, groupby() as year from books group by year order by year asc; select count(distinct author_id) as total_cnt from books; select * from books group by author_id within group order by year desc order by id desc limit 4, 2 option max_matches=6;
